"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[262],{94231:n=>{n.exports=JSON.parse('{"functions":[{"name":"Disconnect","desc":"Disconnects the connection from the signal. May be reconnected later using :Reconnect().\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection = signal:Connect(print, \\"Test:\\")\\n\\nsignal:Fire(\\"Hello world!\\") --\x3e Test: Hello world!\\n\\nconnection:Disconnect()\\n\\nsignal:Fire(\\"Goodbye world!\\")\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":145,"path":"src/init.lua"}},{"name":"Reconnect","desc":"Reconnects the connection to the signal again. If it\'s a :Once connection it will be\\ndisconnected after the next signal fire.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection = signal:Connect(print, \\"Test:\\")\\n\\nsignal:Fire(\\"Hello world!\\") --\x3e Test: Hello world!\\n\\nconnection:Disconnect()\\n\\nsignal:Fire(\\"Goodbye world!\\")\\n\\nconnection:Reconnect()\\n\\nsignal:Fire(\\"Hello again!\\") --\x3e Test: Hello again!\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":197,"path":"src/init.lua"}}],"properties":[{"name":"Connected","desc":"Indicates whether the connection is connected or not.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection = signal:Connect(print, \\"Hello world!\\")\\n\\nprint(connection.Connected) --\x3e true\\n\\nconnection:Disconnect()\\n\\nprint(connection.Connected) --\x3e false\\n```","lua_type":"boolean","readonly":true,"source":{"line":52,"path":"src/init.lua"}}],"types":[{"name":"Connection<U...>","desc":"","fields":[{"name":"Connected","lua_type":"boolean","desc":""},{"name":"Disconnect","lua_type":"(Connection<U...>) -> ()","desc":""},{"name":"Reconnect","lua_type":"(Connection<U...>) -> ()","desc":""}],"source":{"line":32,"path":"src/init.lua"}}],"name":"Connection","desc":"","source":{"line":24,"path":"src/init.lua"}}')}}]);